INSERT INTO public.negative_news VALUES ('6c1a992b-7d45-46f8-aef5-e5ede43a69c3', 'c0000001-0000-0000-0000-000000000049', '2026-04-22', 'Heliogen liquidity concerns mount as cash runway shrinks', 'Reuters', -0.95, NULL, 'Heliogen Inc is under growing scrutiny over its liquidity position, with analysts warning that its cash runway may fall below three quarters absent new financing. The company has not announced a capital raise despite repeated questions from investors.', 'financial_results', 'critical', false, NULL, NULL, NULL, NULL, '2026-06-12 01:45:23.216752+00', 'YzAwMDAwMDEtMDAwMC0wMDAwLTAwMDAtMDAwMDAwMDAwMDQ5fGhlbGlvZ2VuIGxpcXVpZGl0eSBjb25jZXJucyBtb3VudCBhcyBjYXNoIHJ1bndheSBzaHJpbmtzfDIwMjYtMDQtMjI=', true, 'claude', 0.92, 'manual', 0.89);
INSERT INTO public.negative_news VALUES ('c9d60e7e-b7f7-494a-93ef-1b205f692ea4', 'c0000002-0000-0000-0000-000000000004', '2026-05-01', 'Northgate Fabrication faces insolvency risk as anchor customer exits contract', 'Bloomberg', -0.95, NULL, 'Northgate Fabrication is reportedly at risk of insolvency after its largest customer terminated a multi-year supply contract. The loss is estimated to represent a substantial share of annual revenue, raising concerns about the company''s ability to service its obligations.', 'operational', 'critical', false, NULL, NULL, NULL, NULL, '2026-06-12 01:45:24.974881+00', 'YzAwMDAwMDItMDAwMC0wMDAwLTAwMDAtMDAwMDAwMDAwMDA0fG5vcnRoZ2F0ZSBmYWJyaWNhdGlvbiBmYWNlcyBpbnNvbHZlbmN5IHJpc2sgYXMgYW5jaG9yIGN1c3RvbWVyIGV4aXRzIGNvbnRyYWN0fDIwMjYtMDUtMDE=', true, 'claude', 0.92, 'manual', 0.94);
INSERT INTO public.negative_news VALUES ('2c59057d-03d5-423f-83da-d9b5d4fb56ce', 'c0000001-0000-0000-0000-000000000021', '2026-05-02', 'Triumph Group draws covenant waiver as leverage strains balance sheet', 'Reuters', -0.75, NULL, 'Triumph Group has secured a waiver from lenders after breaching financial covenants, according to people familiar with the matter. The aerospace supplier faces continued margin pressure and elevated leverage, raising questions about its near-term liquidity.', 'restructuring', 'high', false, NULL, NULL, NULL, NULL, '2026-06-12 01:45:26.778309+00', 'YzAwMDAwMDEtMDAwMC0wMDAwLTAwMDAtMDAwMDAwMDAwMDIxfHRyaXVtcGggZ3JvdXAgZHJhd3MgY292ZW5hbnQgd2FpdmVyIGFzIGxldmVyYWdlIHN0cmFpbnMgYmFsYW5jZSBzaGVldHwyMDI2LTA1LTAy', true, 'claude', 0.92, 'manual', 0.92);
INSERT INTO public.negative_news VALUES ('107de8e9-c196-4f46-a705-2cd0d6325a2e', 'c0000001-0000-0000-0000-000000000029', '2026-04-30', 'Arconic placed on negative watch by Moody''s', 'Bloomberg', -0.85, NULL, 'Moody''s has placed Arconic Corporation on negative watch, citing weakening margins and elevated leverage. A downgrade would raise the company''s borrowing costs and could trigger covenant pressure on existing facilities.', 'credit_rating', 'high', false, NULL, NULL, NULL, NULL, '2026-06-12 01:45:29.849237+00', 'YzAwMDAwMDEtMDAwMC0wMDAwLTAwMDAtMDAwMDAwMDAwMDI5fGFyY29uaWMgcGxhY2VkIG9uIG5lZ2F0aXZlIHdhdGNoIGJ5IG1vb2R5J3N8MjAyNi0wNC0zMA==', true, 'claude', 0.95, 'manual', 0.88);
INSERT INTO public.negative_news VALUES ('c1dd8124-f872-4008-acaa-a5de9d22f0e1', 'c0000002-0000-0000-0000-000000000001', '2026-04-28', 'Atlas Precision cash flow under pressure amid supply chain disruption', 'Reuters', -0.75, NULL, 'Atlas Precision Manufacturing is facing mounting working-capital strain as prolonged supply chain disruptions delay component deliveries and inflate input costs. Analysts note the company has drawn heavily on its revolving credit facility over the past two quarters.', 'operational', 'high', false, NULL, NULL, NULL, NULL, '2026-06-12 01:45:31.503076+00', 'YzAwMDAwMDItMDAwMC0wMDAwLTAwMDAtMDAwMDAwMDAwMDAxfGF0bGFzIHByZWNpc2lvbiBjYXNoIGZsb3cgdW5kZXIgcHJlc3N1cmUgYW1pZCBzdXBwbHkgY2hhaW4gZGlzcnVwdGlvbnwyMDI2LTA0LTI4', true, 'claude', 0.85, 'manual', 0.91);
