INSERT INTO public.seed_news VALUES ('d4d8e185-91ea-4833-a502-248e2e595a75', 'c0000002-0000-0000-0000-000000000001', 'Atlas Precision Manufacturing', 'Atlas Precision cash flow under pressure amid supply chain disruption', 'Atlas Precision Manufacturing is facing mounting working-capital strain as prolonged supply chain disruptions delay component deliveries and inflate input costs. Analysts note the company has drawn heavily on its revolving credit facility over the past two quarters.', NULL, 'Reuters', '2026-04-28', 0.91, 'manual', '2026-05-24 04:31:04.134708+00');
INSERT INTO public.seed_news VALUES ('9e2a489f-9de0-45d8-83ff-aa6a4ed0c129', 'c0000002-0000-0000-0000-000000000004', 'Northgate Fabrication', 'Northgate Fabrication faces insolvency risk as anchor customer exits contract', 'Northgate Fabrication is reportedly at risk of insolvency after its largest customer terminated a multi-year supply contract. The loss is estimated to represent a substantial share of annual revenue, raising concerns about the company''s ability to service its obligations.', NULL, 'Bloomberg', '2026-05-01', 0.94, 'manual', '2026-05-24 04:31:04.134708+00');
INSERT INTO public.seed_news VALUES ('14028645-d700-40c9-9ddf-eb74aec8af64', 'c0000001-0000-0000-0000-000000000049', 'Heliogen Inc', 'Heliogen liquidity concerns mount as cash runway shrinks', 'Heliogen Inc is under growing scrutiny over its liquidity position, with analysts warning that its cash runway may fall below three quarters absent new financing. The company has not announced a capital raise despite repeated questions from investors.', NULL, 'Reuters', '2026-04-22', 0.89, 'manual', '2026-05-24 04:31:04.134708+00');
INSERT INTO public.seed_news VALUES ('5a449b43-1c5d-452e-aced-2b241c144daf', 'c0000001-0000-0000-0000-000000000029', 'Arconic Corporation', 'Arconic placed on negative watch by Moody''s', 'Moody''s has placed Arconic Corporation on negative watch, citing weakening margins and elevated leverage. A downgrade would raise the company''s borrowing costs and could trigger covenant pressure on existing facilities.', NULL, 'Bloomberg', '2026-04-30', 0.88, 'manual', '2026-05-24 04:31:04.134708+00');
INSERT INTO public.seed_news VALUES ('dad165a8-4b61-4d2d-b56a-b86e3e5d2cb6', 'c0000001-0000-0000-0000-000000000021', 'Triumph Group Inc', 'Triumph Group draws covenant waiver as leverage strains balance sheet', 'Triumph Group has secured a waiver from lenders after breaching financial covenants, according to people familiar with the matter. The aerospace supplier faces continued margin pressure and elevated leverage, raising questions about its near-term liquidity.', NULL, 'Reuters', '2026-05-02', 0.92, 'manual', '2026-05-25 01:34:44.366941+00');
INSERT INTO public.seed_sec_filings VALUES ('0d970f3a-52b0-41bf-a82b-32659b62c483', '0001840292', 'Heliogen, Inc.', '10-K', '2025-03-27', '0001840292-25-000012', 'https://www.sec.gov/Archives/edgar/data/1840292/000184029225000012/hlg-20241231.htm', '{going_concern_warning,cash_runway_<3_quarters}', 'Auditor expressed substantial doubt about the company''s ability to continue as a going concern; cash runway under three quarters.', 'edgar', '2026-05-23 01:12:29.515286+00');
